insert into _study_payload_hq_dbmatch(data) values ('[{"event_code": "evt_n001", "book_name": "창세기", "testament": "OT", "book_order_num": 1, "event_order_num": 1, "section": "태초와 족장", "section_order": 1, "emoji": "🌌", "snippet": "하나님이 말씀으로 세상을 창조하시고 안식으로 완성하신다.", "quote": "“태초에 하나님이 천지를 창조하시니라.” (창 1:1-2:3)", "box_title": "창조: 7일과 안식 핵심 메시지", "points": [{"order_num": 1, "bold_label": "서사 포인트:", "content": "창조: 7일과 안식 사건의 핵심은 하나님이 말씀으로 세상을 창조하시고 안식으로 완성하신다."}, {"order_num": 2, "bold_label": "문맥 연결:", "content": "창 1:1-2:3 본문은 \"하나님이 가라사대 천하의 물이 한 곳으로 모이고 뭍이 드러나라 하시매 그대로 되니라.\"라는 장면을 통해 사건의 신학적 방향을 밝혀 준다."}, {"order_num": 3, "bold_label": "공동체 적용:", "content": "혼돈처럼 보이는 상황에서도 하나님의 말씀은 질서를 회복하신다는 믿음을 붙들어야 한다."}], "verse_pages": [{"order_num": 1, "ref": "창 1:1-2:3", "text": ""}]}, {"event_code": "evt_n002", "book_name": "창세기", "testament": "OT", "book_order_num": 1, "event_order_num": 2, "section": "태초와 족장", "section_order": 1, "emoji": "🌌", "snippet": "사람은 에덴에서 돌보고 지키는 사명을 받는다.", "quote": "“여호와 하나님이 천지를 창조하신 때에 천지의 창조된 대략이 이러하니라.” (창 2:4-25)", "box_title": "에덴: 사람의 창조와 사명 핵심 메시지", "points": [{"order_num": 1, "bold_label": "구속사 포인트:", "content": "에덴: 사람의 창조와 사명 사건의 핵심은 사람은 에덴에서 돌보고 지키는 사명을 받는다."}, {"order_num": 2, "bold_label": "문맥 연결:", "content": "창 2:4-25 본문은 \"여호와 하나님이 그 땅에서 보기에 아름답고 먹기에 좋은 나무가 나게 하시니 동산 가운데에는 생명 나무와 선악을 알게 하는 나무도 있더라.\"라는 장면을 통해 사건의 신학적 방향을 밝혀 준다."}, {"order_num": 3, "bold_label": "공동체 적용:", "content": "출발점이 흔들릴수록 피조물의 자리가 아니라 창조주의 주권을 먼저 고백해야 한다."}], "verse_pages": [{"order_num": 1, "ref": "창 2:4-25", "text": ""}]}, {"event_code": "evt_n003", "book_name": "창세기", "testament": "OT", "book_order_num": 1, "event_order_num": 3, "section": "태초와 족장", "section_order": 1, "emoji": "⚖️", "snippet": "유혹은 의심을 만들고, 선택은 관계의 균열로 이어진다.", "quote": "“여호와 하나님의 지으신 들짐승 중에 뱀이 가장 간교하더라 뱀이 여자에게 물어 가로되 하나님이 참 으로 너희더러 동산 모든 나무의 실과를 먹지 말라 하시더냐.” (창 3:1-13)", "box_title": "타락: 뱀의 유혹과 선택 핵심 메시지", "points": [{"order_num": 1, "bold_label": "장면 해설:", "content": "타락: 뱀의 유혹과 선택 사건의 핵심은 유혹은 의심을 만들고, 선택은 관계의 균열로 이어진다."}, {"order_num": 2, "bold_label": "문맥 연결:", "content": "창 3:1-13 본문은 \"뱀이 여자에게 이르되 너희가 결코 죽지 아니하리라.\"라는 장면을 통해 사건의 신학적 방향을 밝혀 준다."}, {"order_num": 3, "bold_label": "공동체 적용:", "content": "심판의 본문은 두려움을 넘어서 회개로 부르시는 하나님의 자비를 함께 읽게 한다."}], "verse_pages": [{"order_num": 1, "ref": "창 3:1-13", "text": ""}]}, {"event_code": "evt_n004", "book_name": "창세기", "testament": "OT", "book_order_num": 1, "event_order_num": 4, "section": "태초와 족장", "section_order": 1, "emoji": "🌌", "snippet": "죄의 결과로 사람은 에덴을 떠나고, 길은 막힌다.", "quote": "“여호와 하나님이 뱀에게 이르시되 네가 이렇게 하였으니 네가 모든 육축과 들의 모든 짐승보다 더 욱 저주를 받아 배로 다니고 종신토록 흙을 먹을지니라.” (창 3:14-24)", "box_title": "추방: 동산 밖으로 핵심 메시지", "points": [{"order_num": 1, "bold_label": "핵심 메시지:", "content": "추방: 동산 밖으로 사건의 핵심은 죄의 결과로 사람은 에덴을 떠나고, 길은 막힌다."}, {"order_num": 2, "bold_label": "문맥 연결:", "content": "창 3:14-24 본문은 \"또 여자에게 이르시되 내가 네게 잉태하는 고통을 크게 더하리니 네가 수고하고 자식을 낳을 것이 며 너는 남편을 사모하고 남편은 너를 다스릴 것이니라 하시고.\"라는 장면을 통해 사건의 신학적 방향을 밝혀 준다."}, {"order_num": 3, "bold_label": "공동체 적용:", "content": "혼돈처럼 보이는 상황에서도 하나님의 말씀은 질서를 회복하신다는 믿음을 붙들어야 한다."}], "verse_pages": [{"order_num": 1, "ref": "창 3:14-24", "text": ""}]}, {"event_code": "evt_n005", "book_name": "창세기", "testament": "OT", "book_order_num": 1, "event_order_num": 5, "section": "태초와 족장", "section_order": 1, "emoji": "📖", "snippet": "분노가 다스려지지 않자 형제가 형제를 해친다.", "quote": "“아담이 그 아내 하와와 동침하매 하와가 잉태하여 가인을 낳고 이르되 내가 여호와로 말미암아 득남 하였다 하니라.” (창 4:1-16)", "box_title": "가인과 아벨: 들판의 비극 핵심 메시지", "points": [{"order_num": 1, "bold_label": "서사 포인트:", "content": "가인과 아벨: 들판의 비극 사건의 핵심은 분노가 다스려지지 않자 형제가 형제를 해친다."}, {"order_num": 2, "bold_label": "문맥 연결:", "content": "창 4:1-16 본문은 \"가인과 그 제물은 열납하지 아니하신지라 가인이 심히 분하여 안색이 변하니.\"라는 장면을 통해 사건의 신학적 방향을 밝혀 준다."}, {"order_num": 3, "bold_label": "공동체 적용:", "content": "본문의 메시지를 정보로 끝내지 말고, 오늘의 선택과 관계 속에서 살아내야 한다."}], "verse_pages": [{"order_num": 1, "ref": "창 4:1-16", "text": ""}]}, {"event_code": "evt_n006", "book_name": "창세기", "testament": "OT", "boo